import scala.collection.mutable.{PriorityQueue, HashMap}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val graph = HashMap[Long, List[Long]].withDefaultValue(Nil)
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    graph(u) = w :: graph(u)
    graph(v) = w :: graph(v)
  }

  val parent = Array.fill(n.toInt)(-1)
  val rank = Array.fill(n.toInt)(1)

  def find(x: Long): Long = {
    if (parent(x.toInt) != x) {
      parent(x.toInt) = find(parent(x.toInt))
    }
    parent(x.toInt)
  }

  def union(x: Long, y: Long): Boolean = {
    val rootX = find(x)
    val rootY = find(y)
    if (rootX == rootY) false
    else {
      if (rank(rootX) > rank(rootY)) {
        parent(rootY.toInt) = rootX
      } else {
        parent(rootX.toInt) = rootY
        if (rank(rootX) == rank(rootY)) rank(rootY.toInt) += 1
      }
      true
    }
  }

  val pq = PriorityQueue[Long](Ordering.Long.reverse)
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    pq.enqueue(w)
  }

  var components = n.toInt
  var result = 0L

  while (components > k) {
    val w = pq.dequeue
    val u = find(0)
    val v = find(1)
    if (union(u, v)) {
      components -= 1
      result = w
    }
  }

  result
}
