  def edges(arr: Array[Array[Long]]): Long = {
    def k(k: Long): Long = {
      val graph = mutable.HashMap[Long, mutable.Set[Long]]()
      for (edge <- arr) {
        val u = edge(0)
        val v = edge(1)
        if (!graph.contains(u)) graph(u) = mutable.Set[Long]()
        if (!graph.contains(v)) graph(v) = mutable.Set[Long]()
        graph(u) += v
        graph(v) += u
      }

      val parent = mutable.HashMap[Long, Long]()
      val rank = mutable.HashMap[Long, Int]()

      def find(x: Long): Long = {
        if (parent(x) != x) parent(x) = find(parent(x))
        parent(x)
      }

      def union(x: Long, y: Long): Boolean = {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) false
        else {
          if (rank(rootX) > rank(rootY)) {
            parent(rootY) = rootX
          } else {
            parent(rootX) = rootY
            if (rank(rootX) == rank(rootY)) rank(rootY) += 1
          }
          true
        }
      }

      for (u <- graph.keys) {
        parent(u) = u
        rank(u) = 1
      }

      val edgesSorted = arr.sortBy(-_.apply(2))
      val maxCost = mutable.HashMap[Long, Long]()

      for (edge <- edgesSorted) {
        val u = edge(0)
        val v = edge(1)
        val w = edge(2)
        if (union(u, v)) {
          val root = find(u)
          maxCost(root) = math.max(maxCost.getOrElse(root, 0), w)
        }
      }

      val components = mutable.HashMap[Long, Long]()

      for (u <- graph.keys) {
        val root = find(u)
        if (!components.contains(root)) {
          components(root) = maxCost.getOrElse(root, 0)
        }
      }

      val componentValues = components.values.toArray
      componentValues.sortInPlace()
      if (componentValues.length <= k) {
        componentValues.last
      } else {
        val threshold = componentValues(componentValues.length - k)
        threshold
      }
    }

    k
  }

  edges
}
